    found = False
    for entry in data_entries:
        # Success: Must have all required fields ('jobTitle', 'name', 'email')
        if (
            entry.get("statusCode") == 201 and
            all(field in entry for field in ("jobTitle", "name", "email"))
        ):
            found = True
            payload = {
                "jobTitle": entry["jobTitle"],
                "name": entry["name"],
                "email": entry["email"]
            }
            # Optional property
            if "id" in entry:
                payload["id"] = entry["id"]
            # Validate against request schema (prior to sending)
